# apply-logging-fix.ps1
# Bug-fixes + detailed logging across the OLCVPN iOS app.
# Run from the repo root (C:\OLCVPN\OLCVPN-ios-unsigned):
#   powershell -ExecutionPolicy Bypass -File .\apply-logging-fix.ps1
$ErrorActionPreference = 'Stop'
$root = (Get-Location).Path
if (-not (Test-Path (Join-Path $root 'project.yml'))) {
  Write-Error 'project.yml not found. Run this script from the OLCVPN repo root.'
  exit 1
}
function Write-FileB64($rel, $b64) {
  $path = Join-Path $root $rel
  $dir  = Split-Path $path -Parent
  if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
  $bytes = [System.Convert]::FromBase64String($b64)
  [System.IO.File]::WriteAllBytes($path, $bytes)
  Write-Host ('  wrote: ' + $rel)
}

Write-Host 'Writing files...'
Write-FileB64 'Shared/DiagLog.swift' ''
Write-FileB64 'Shared/OLCCore.swift' ''
Write-FileB64 'Shared/SharedConfig.swift' ''
Write-FileB64 'Shared/KeychainHelper.swift' ''
Write-FileB64 'App/Model/ConfigStore.swift' ''
Write-FileB64 'App/Model/OLCUri.swift' ''
Write-FileB64 'App/Model/PingService.swift' ''
Write-FileB64 'App/OLCVPNApp.swift' ''
Write-FileB64 'App/VPN/ProxyManager.swift' ''
Write-FileB64 'App/VPN/TunnelManager.swift' ''
Write-FileB64 'App/Views/DiagnosticsView.swift' ''
Write-FileB64 'App/Views/ProfileEditView.swift' ''
Write-FileB64 'OLCTunnel/PacketTunnelProvider.swift' ''
Write-FileB64 'OLCTunnel/Tun2Socks.swift' ''

Write-Host 'Verifying written files (sha256)...'
# Таблица ожидаемых sha256 (получены из чистых файлов на момент создания патча).
$expected = @{
  'Shared/DiagLog.swift'                 = '1c32bc0c4d27b84288d88043711212036d3e76824d487fffbee11c1a2ddb76e4'
  'Shared/OLCCore.swift'                 = '2dad04fab7eb47ce5da850f77361837f8875a7a08d99333c53ed342a9b6b4b97'
  'Shared/SharedConfig.swift'            = '2953d12e668b6f907edb11decc4d177486e7052d7663375431acf0b64e3d2e8c'
  'Shared/KeychainHelper.swift'          = 'b365a39a7b1b5802d389d7dbad8cc45207978a75e760e6beee41f50cdd8d8acb'
  'App/Model/ConfigStore.swift'          = 'd728514ce1cd0b0356f143b81a586b08faf0a438d425f6e22d1aa13d52144428'
  'App/Model/OLCUri.swift'               = '1023eee2fe7bf590966d05c3ab1bede3e3bb82dcf7e8b76cadf5574c411bbb11'
  'App/Model/PingService.swift'          = '2b9c3f437b0c09db9dc4c2117e3752eacc028c32b31a0898b1b97f19a39cba07'
  'App/OLCVPNApp.swift'                  = '2eeb012e0f696b5ef8b55892a133ca6520547248eaad383515c7fcf636a1bd14'
  'App/VPN/ProxyManager.swift'           = 'ac04ae4f98f34268f91a3af70df9b33aab9b8e8f42f5998d8018f518121730f3'
  'App/VPN/TunnelManager.swift'          = '6d61e283a2f9a25419392ed00fbf0d02affd85de21ef1f07076150a5c03340d7'
  'App/Views/DiagnosticsView.swift'      = 'd475cebba20f1d74ea42a604862b76f2e0229e7d08d4433ccec698d23a8fa448'
  'App/Views/ProfileEditView.swift'      = 'c1240300564fc8005c9f6bc50f9e5a79053f054a14dfa8704530ea00f23233c9'
  'OLCTunnel/PacketTunnelProvider.swift' = 'e0bd74dc62a47cae39999a77961b6f2d71e7b6e819a04c4311e11b2427582b22'
  'OLCTunnel/Tun2Socks.swift'            = '555832a5c1f274f26db41f27c7d4ab572c8f5f48d9f32e5cfcad71534f60070b'
}
$verifyFail = 0
foreach ($kv in $expected.GetEnumerator()) {
  $rel = $kv.Key
  $want = $kv.Value
  $got = (Get-FileHash (Join-Path $root $rel) -Algorithm SHA256).Hash.ToLower()
  if ($got -ne $want) {
    Write-Host ('  MISMATCH ' + $rel + ' want=' + $want + ' got=' + $got)
    $verifyFail++
  } else {
    Write-Host ('  ok: ' + $rel)
  }
}
if ($verifyFail -gt 0) { Write-Error ($verifyFail.ToString() + ' sha mismatches after write'); exit 1 }

Write-Host ''
Write-Host 'Creating feature branch and committing...'
$branch = 'feat/logging-and-bugfixes'
# Создаём ветку, если её ещё нет; иначе переключаемся на существующую.
$existing = git branch --list $branch
if ([string]::IsNullOrWhiteSpace($existing)) {
  git checkout -b $branch
  if ($LASTEXITCODE -ne 0) { Write-Error 'git checkout -b failed'; exit 1 }
} else {
  git checkout $branch
  if ($LASTEXITCODE -ne 0) { Write-Error 'git checkout failed'; exit 1 }
}
git add -A
if ($LASTEXITCODE -ne 0) { Write-Error 'git add failed'; exit 1 }
$msg = @(
  'fix(logging+app): detailed logs via debug toggle + bug fixes'
  ''
  'Bug fixes:'
  '- OLCVPNApp: import olcrtc:// via do/catch instead of swallowing parse errors (try?)'
  '- PacketTunnelProvider: capture olcRTC core logs (CoreLogCapture + setLogWriter) so [pc]/[ice]/jitsi/smux are visible inside the VPN tunnel'
  '- ProxyManager: remove data race on activeSocksPort (capture immutable copy on main)'
  '- Tun2Socks: make hev log-level configurable (info when debug, warn otherwise)'
  '- TunnelManager: de-duplicate and clear stale lastError on connected'
  '- DiagnosticsView: cancel stale reload tasks to avoid overlapping Task spam'
  '- ProfileEditView: surface feedback + log when key is missing (copyLink/runPing)'
  ''
  'Logging:'
  '- DiagLog: add debugEnabled flag + debug()/error() helpers (errors always on)'
  '- OLCCore: per Go-call in/out/NSError timings (keyHex not dumped, only length)'
  '- SharedConfig/KeychainHelper/ConfigStore/OLCUri/PingService: trace + error logs'
  '- TunnelManager/ProxyManager: phase logs (prepare/save/startVPN/IPC) + error logs'
  '- debug toggle wired from AppSettings (app) and cfg.debug (extension)'
) -join "`n"
git commit -m $msg
if ($LASTEXITCODE -ne 0) { Write-Error 'git commit failed'; exit 1 }
Write-Host ''
Write-Host 'Pushing to origin...'
git push -u origin $branch 2>&1 | Write-Host
if ($LASTEXITCODE -ne 0) { Write-Error 'git push failed'; exit 1 }
Write-Host ''
Write-Host ('Done. Branch pushed: ' + $branch)
Write-Host ('Open a PR: https://github.com/lucudar/OLCVPN/pull/new/' + $branch)
